script:
frappe.ui.form.on('Rental Contract', {
    refresh(frm) {
        // Show PO fields only if PO is required
        frm.toggle_display('po_number', frm.doc.po_required);
        frm.toggle_display('po_total_value', frm.doc.po_required);
    },

    po_required(frm) {
        // Show/hide PO fields when checkbox is toggled
        frm.toggle_display('po_number', frm.doc.po_required);
        frm.toggle_display('po_total_value', frm.doc.po_required);
    },

    contract_end_date(frm) {
        // Warn immediately if end date is before start date
        if (frm.doc.contract_start_date && frm.doc.contract_end_date) {
            if (frm.doc.contract_end_date <= frm.doc.contract_start_date) {
                frappe.msgprint({
                    message: 'End Date must be after Start Date.',
                    indicator: 'red'
                });
                frm.set_value('contract_end_date', '');
            }
        }
    }
});
